import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import Timer from './Timer';
import AntiCheating from '../utils/antiCheating';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [antiCheating, setAntiCheating] = useState(null);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        setQuestions(response.data.questions);
        setLoading(false);
      } catch (error) {
        console.error('Failed to fetch questions:', error);
        setError('Failed to load questions. Please refresh the page.');
        setLoading(false);
      }
    };

    fetchQuestions();
  }, [quizId]);

  useEffect(() => {
    // Initialize anti-cheating measures
    if (quizId && !antiCheating) {
      const ac = new AntiCheating(
        quizId,
        (count) => setTabSwitchCount(count),
        () => {
          // Handle fullscreen exit - could auto-submit after multiple violations
          if (tabSwitchCount >= 3) {
            handleAutoSubmit();
          }
        }
      );
      setAntiCheating(ac);
    }

    return () => {
      if (antiCheating) {
        antiCheating.cleanup();
      }
    };
  }, [quizId, tabSwitchCount]);

  const handleOptionSelect = (questionId, option) => {
    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Automatically move to next question after selection
    setTimeout(() => {
      if (currentQuestionIndex < questions.length - 1) {
        setCurrentQuestionIndex(prev => prev + 1);
      }
    }, 300);
  };

  const handleSubmitQuiz = useCallback(async () => {
    if (submitting) return;

    setSubmitting(true);

    try {
      const answersList = Object.entries(answers).map(([questionId, selectedOption]) => ({
        question_id: parseInt(questionId),
        selected_option: selectedOption
      }));

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCount
      });

      onSubmit({
        score: response.data.score,
        totalQuestions: response.data.total_questions,
        timeTaken: response.data.time_taken_microseconds
      });

    } catch (error) {
      console.error('Failed to submit quiz:', error);
      setError('Failed to submit quiz. Please try again.');
      setSubmitting(false);
    }
  }, [quizId, answers, tabSwitchCount, onSubmit, submitting]);

  const handleAutoSubmit = useCallback(() => {
    if (!submitting && Object.keys(answers).length > 0) {
      handleSubmitQuiz();
    }
  }, [answers, handleSubmitQuiz, submitting]);

  const handleTimeUp = () => {
    handleAutoSubmit();
    onTimeout();
  };

  if (loading) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center' }}>
          <h2>Loading questions...</h2>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center' }}>
          <h2>Error</h2>
          <p style={{ color: '#f56565', margin: '20px 0' }}>{error}</p>
          <button className="btn" onClick={() => window.location.reload()}>
            Refresh Page
          </button>
        </div>
      </div>
    );
  }

  const currentQuestion = questions[currentQuestionIndex];
  const hasAnsweredCurrent = answers[currentQuestion?.id] !== undefined;
  const allAnswered = Object.keys(answers).length === questions.length;

  return (
    <div className="container">
      <div className="card">
        <div className="quiz-header">
          <span className="question-number">
            Q{currentQuestionIndex + 1}/{questions.length}
          </span>
          <Timer 
            initialSeconds={1800} // 30 minutes
            onTimeUp={handleTimeUp}
            isActive={!submitting}
          />
        </div>

        {tabSwitchCount > 0 && (
          <div className="warning-message">
            Warning: Tab switching detected ({tabSwitchCount} time{tabSwitchCount !== 1 ? 's' : ''})
          </div>
        )}

        <div className="question-text">
          {currentQuestion?.question}
        </div>

        <div className="options-grid">
          {currentQuestion?.options.map((option, index) => (
            <div
              key={index}
              className={`option ${answers[currentQuestion.id] === option ? 'selected' : ''}`}
              onClick={() => !submitting && handleOptionSelect(currentQuestion.id, option)}
            >
              {option}
            </div>
          ))}
        </div>

        {allAnswered && !submitting && (
          <button 
            className="btn btn-secondary"
            onClick={handleSubmitQuiz}
            style={{ marginTop: '20px' }}
          >
            Submit Quiz
          </button>
        )}

        {submitting && (
          <div style={{ textAlign: 'center', marginTop: '20px', color: '#718096' }}>
            Submitting your answers...
          </div>
        )}
      </div>
    </div>
  );
};

export default QuizPage;
